import{_ as e,o as a,c as d,a2 as o}from"./chunks/framework.Dvn0Uh9o.js";const g=JSON.parse('{"title":"Validation","description":"","frontmatter":{},"headers":[],"relativePath":"validation/index.md","filePath":"validation/index.md","lastUpdated":1783378229000}'),r={name:"validation/index.md"};function i(n,t,l,s,c,h){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>mobx-react-form ships with a <strong>pluggable validation system</strong>. You can choose one or more validation backends (called <em>drivers</em>) and attach them to the form at initialization. Each driver is responsible for validating each field and pushing error messages into the field&#39;s <code>validationErrorStack</code>.</p><p>Validation can be triggered:</p><ul><li><strong>Automatically</strong> — on field blur, change, form init, submit, clear, reset (configurable via options)</li><li><strong>Manually</strong> — via <code>form.validate()</code>, <code>field.validate()</code>, or <code>form.submit()</code></li></ul><blockquote><p>For a deeper dive into the validation lifecycle (what happens when, in what order), see the <a href="./lifecycle">Validation Lifecycle</a> page.</p></blockquote><hr><h2 id="choosing-a-validation-plugin" tabindex="-1">Choosing a Validation Plugin <a class="header-anchor" href="#choosing-a-validation-plugin" aria-label="Permalink to &quot;Choosing a Validation Plugin&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Style</th><th>Driver</th><th>Best For</th><th>Example</th></tr></thead><tbody><tr><td><strong>Custom functions</strong></td><td>VJF</td><td>Full control, custom logic, server checks</td><td><code>({ field }) =&gt; [field.value.length &gt; 3, &#39;Too short&#39;]</code></td></tr><tr><td><strong>Declarative rules</strong></td><td>DVR</td><td>Simple string-based rules (like Laravel)</td><td><code>&#39;required or email or min:5&#39;</code></td></tr><tr><td><strong>JSON Schema</strong></td><td>SVK</td><td>JSON-first projects, API compatibility</td><td><code>{ type: &#39;string&#39;, minLength: 3 }</code></td></tr><tr><td><strong>Object schema</strong></td><td>YUP</td><td>Modern JS/TS, chainable API</td><td><code>y.string().required().min(3)</code></td></tr><tr><td><strong>Object schema</strong></td><td>JOI</td><td>Enterprise-grade, rich error messages</td><td><code>j.string().min(3).required()</code></td></tr><tr><td><strong>TypeScript schema</strong></td><td>ZOD</td><td>TypeScript-first, type inference</td><td><code>z.string().min(3)</code></td></tr></tbody></table><h3 id="when-to-use-what" tabindex="-1">When to use what <a class="header-anchor" href="#when-to-use-what" aria-label="Permalink to &quot;When to use what&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Use Case</th><th>Recommended</th></tr></thead><tbody><tr><td>Simple forms with basic rules</td><td><strong>DVR</strong> — fastest to write</td></tr><tr><td>Full control over validation logic</td><td><strong>VJF</strong> — write any function</td></tr><tr><td>JSON Schema compliance (API validation)</td><td><strong>SVK</strong> — standards-based</td></tr><tr><td>Modern object-oriented validation</td><td><strong>YUP</strong> — popular, good DX</td></tr><tr><td>Enterprise / complex schemas</td><td><strong>JOI</strong> — battle-tested, rich errors</td></tr><tr><td>TypeScript-native with infer</td><td><strong>ZOD</strong> — best TS integration</td></tr></tbody></table><h3 id="can-i-use-multiple-plugins" tabindex="-1">Can I use multiple plugins? <a class="header-anchor" href="#can-i-use-multiple-plugins" aria-label="Permalink to &quot;Can I use multiple plugins?&quot;">​</a></h3><p><strong>Yes.</strong> You can enable multiple plugins simultaneously. Validation runs through all enabled drivers in sequence (configurable via <code>validationPluginsOrder</code>). If <code>stopValidationOnError</code> is <code>true</code>, subsequent drivers are skipped once a field has an error.</p><hr><h2 id="plugin-comparison" tabindex="-1">Plugin Comparison <a class="header-anchor" href="#plugin-comparison" aria-label="Permalink to &quot;Plugin Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>VJF</th><th>DVR</th><th>SVK</th><th>YUP</th><th>JOI</th><th>ZOD</th></tr></thead><tbody><tr><td><strong>Custom validation functions</strong></td><td>✅ Native</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><strong>String-based rules</strong></td><td>❌</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><strong>JSON Schema</strong></td><td>❌</td><td>❌</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><strong>Chainable API</strong></td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Async validation</strong></td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><strong>Extend with custom rules</strong></td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><strong>Automatic error messages</strong></td><td>User-defined</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>TypeScript inference</strong></td><td>No</td><td>No</td><td>No</td><td>Partial</td><td>Partial</td><td>✅</td></tr></tbody></table><blockquote><p><strong>VJF</strong>, <strong>DVR</strong> and <strong>SVK</strong> support async validation and custom extension (via the <code>extend</code> callback). <strong>YUP</strong>, <strong>JOI</strong> and <strong>ZOD</strong> do not support the <code>extend</code> callback or async validation pipelines — they rely on their own native APIs for those features.</p></blockquote><hr><h2 id="setup-pages" tabindex="-1">Setup Pages <a class="header-anchor" href="#setup-pages" aria-label="Permalink to &quot;Setup Pages&quot;">​</a></h2><h3 id="choose-your-plugin" tabindex="-1">Choose your plugin <a class="header-anchor" href="#choose-your-plugin" aria-label="Permalink to &quot;Choose your plugin&quot;">​</a></h3><ul><li><a href="./plugins/VJF/setup">Setup VJF — Vanilla JavaScript Functions</a></li><li><a href="./plugins/DVR/setup">Setup DVR — Declarative Validation Rules</a></li><li><a href="./plugins/SVK/setup">Setup SVK — Schema Validation Keywords</a></li><li><a href="./plugins/YUP/setup">Setup YUP — Object Schema Validator</a></li><li><a href="./plugins/JOI/setup">Setup JOI — Object Schema Validator</a></li><li><a href="./plugins/ZOD/setup">Setup ZOD — TypeScript-First Schema Validation</a></li></ul><h3 id="extend-with-custom-rules" tabindex="-1">Extend with custom rules <a class="header-anchor" href="#extend-with-custom-rules" aria-label="Permalink to &quot;Extend with custom rules&quot;">​</a></h3><blockquote><p>Available only for <strong>VJF</strong>, <strong>DVR</strong> and <strong>SVK</strong>.</p></blockquote><ul><li><a href="./plugins/VJF/extend">Extend VJF — Custom Validation Functions</a></li><li><a href="./plugins/DVR/extend">Extend DVR — Custom Declarative Rules</a></li><li><a href="./plugins/SVK/extend">Extend SVK — Custom JSON Schema Keywords</a></li></ul><h3 id="async-validation" tabindex="-1">Async validation <a class="header-anchor" href="#async-validation" aria-label="Permalink to &quot;Async validation&quot;">​</a></h3><blockquote><p>Available only for <strong>VJF</strong>, <strong>DVR</strong> and <strong>SVK</strong>.</p></blockquote><ul><li><a href="./plugins/VJF/async">Async VJF</a></li><li><a href="./plugins/DVR/async">Async DVR</a></li><li><a href="./plugins/SVK/async">Async SVK</a></li></ul><hr><h2 id="related-guides" tabindex="-1">Related Guides <a class="header-anchor" href="#related-guides" aria-label="Permalink to &quot;Related Guides&quot;">​</a></h2><ul><li><a href="./lifecycle">Validation Lifecycle</a> — when validation fires, field filtering, plugin ordering</li><li><a href="./../error-handling">Error Handling</a> — <code>submitThrowsError</code>, <code>defaultGenericError</code>, server error mapping</li><li><a href="./../performance-ssr">Performance &amp; SSR</a> — <code>validationDebounceWait</code>, <code>stopValidationOnError</code>, validation triggers</li><li><a href="./../actions/validate">Validation &amp; Submit Actions</a> — <code>validate()</code>, <code>submit()</code>, <code>check()</code>, <code>invalidate()</code></li><li><a href="./../events/validation-hooks">Validation Hooks</a> — <code>onSuccess</code>, <code>onError</code>, extending hooks</li></ul>',30)])])}const p=e(r,[["render",i]]);export{g as __pageData,p as default};
